  ('medical-tech-moex-07955', 'medical-tech', 'medical-tech-moex-106-bccd9a5a', 'sub-medical-tech-05', NULL, 'single_choice', '有關抗生素溶液之配製保存方法，下列敘述何者錯誤？', '["通常先配好高濃度溶液，分裝儲存於-70℃，要使用時再稀釋", "抗生素可重複冷凍解凍數次仍然堪用", "用來測定MIC之抗生素必須使用標準品，詳細之配製流程需以CLSI之步驟為依據", "有些抗生素以水稀釋即可，有些要用特定pH值及濃度之緩衝液（buffer）配製"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:16:32+00:00", "source_pdf_sha1": "8e4a65d4b75e", "answer_pdf_sha1": "1b85c79554b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "106020", "c": "308", "s": "44", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學與臨床微生物學（包括細菌與黴菌）", "year": "106", "exam_name": "106年第一次專技人員高等考試醫師牙醫師藥師考試分階段考試、藥師、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸治療師、獸醫師考試", "original_question_number": 52, "answer_corrected": false, "flags": ["answer_missing"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
